// In service.go — declare input type with compile-time Validator assertion
var _ models.Validator = (*GetLatestPriceInput)(nil)

type GetLatestPriceInput struct {
    Namespace string
    Provider  Provider
    ModelID   string
}

func (i GetLatestPriceInput) Validate() error {
    var errs []error
    if i.Provider == "" { errs = append(errs, ErrProviderEmpty) }
    if i.ModelID == "" { errs = append(errs, ErrModelIDEmpty) }
    return models.NewNillableGenericValidationError(errors.Join(errs...))
}

// In openmeter/meter/service/manage.go
func (s *ManageService) CreateMeter(ctx context.Context, input meter.CreateMeterInput) (meter.Meter, error) {
    if err := input.Validate(); err != nil {
        return meter.Meter{}, err
    }
    created, err := s.adapter.CreateMeter(ctx, input)
    if err != nil {
        return meter.Meter{}, err
    }
    ev := meter.NewMeterCreateEvent(ctx, &created)
    if err := s.publisher.Publish(ctx, ev); err != nil {
        s.logger.Error("failed to publish meter create event", "error", err)
    }
    return created, nil
}
